import { Link } from "react-router-dom";

function LeagueMenu() {
    return (
        <div className="league-menu">
            <h1>League Menu</h1>
            <div className="menu-options">
                <Link to="/team-selection" className="menu-link">
                    <button className="menu-button">Play</button>
                </Link>
                <Link to="/new-match" className="menu-link">
                    <button className="menu-button">New Match</button>
                </Link>
                <Link to="/team-list" className="menu-link">
                    <button className="menu-button">View Team List</button>
                </Link>
            </div>
        </div>
    );
}
